/**
 * 异步存储模块
 * 适用于高吞吐量、低延迟的异步操作场景
 * 特点：非阻塞、队列化写入、批量操作、缓存优化
 */

import { StorageConfig, StorageKeys } from './config.js'

class AsyncStorage {
  constructor() {
    this.cache = new Map()
    this.writeQueue = []
    this.isProcessing = false
    this.pendingWrites = new Map()
    this.initialized = false
  }

  async init() {
    if (this.initialized) return
    const loadPromises = StorageConfig.asyncKeys.map(async key => {
      try {
        const value = await this._getRaw(key)
        if (value !== null) {
          this.cache.set(key, { value, timestamp: Date.now() })
        }
      } catch (e) {
        console.warn(`[AsyncStorage] 初始化缓存失败: ${key}`, e)
      }
    })
    await Promise.all(loadPromises)
    this.initialized = true
  }

  _getRaw(key) {
    return new Promise((resolve, reject) => {
      uni.getStorage({
        key,
        success: (res) => resolve(res.data),
        fail: () => resolve(null)
      })
    })
  }

  _setRaw(key, data) {
    return new Promise((resolve, reject) => {
      uni.setStorage({
        key,
        data,
        success: resolve,
        fail: reject
      })
    })
  }

  _removeRaw(key) {
    return new Promise((resolve, reject) => {
      uni.removeStorage({
        key,
        success: resolve,
        fail: reject
      })
    })
  }

  async set(key, value, options = {}) {
    const { ttl = null, immediate = false } = options
    const cacheEntry = {
      value,
      timestamp: Date.now(),
      ttl
    }
    this.cache.set(key, cacheEntry)

    if (immediate) {
      try {
        await this._setRaw(key, value)
        return { success: true, error: null }
      } catch (e) {
        console.error(`[AsyncStorage] 立即写入失败: ${key}`, e)
        return { success: false, error: e }
      }
    }

    this.pendingWrites.set(key, value)
    this._scheduleWrite()

    return { success: true, error: null, queued: true }
  }

  async get(key, defaultValue = null) {
    const cached = this.cache.get(key)
    if (cached) {
      if (cached.ttl && Date.now() - cached.timestamp > cached.ttl) {
        this.cache.delete(key)
      } else {
        return cached.value
      }
    }

    try {
      const value = await this._getRaw(key)
      if (value !== null) {
        this.cache.set(key, { value, timestamp: Date.now() })
        return value
      }
      return defaultValue
    } catch (e) {
      console.error(`[AsyncStorage] 读取失败: ${key}`, e)
      return defaultValue
    }
  }

  async remove(key) {
    this.cache.delete(key)
    this.pendingWrites.delete(key)
    try {
      await this._removeRaw(key)
      return { success: true, error: null }
    } catch (e) {
      console.error(`[AsyncStorage] 删除失败: ${key}`, e)
      return { success: false, error: e }
    }
  }

  async clear() {
    this.cache.clear()
    this.pendingWrites.clear()
    const clearPromises = StorageConfig.asyncKeys.map(key => this._removeRaw(key))
    await Promise.allSettled(clearPromises)
    return { success: true }
  }

  _scheduleWrite() {
    if (this.isProcessing) return
    setTimeout(() => this._processQueue(), 50)
  }

  async _processQueue() {
    if (this.isProcessing || this.pendingWrites.size === 0) return
    this.isProcessing = true

    const writes = Array.from(this.pendingWrites.entries())
    this.pendingWrites.clear()

    const promises = writes.map(([key, value]) => 
      this._setRaw(key, value).catch(e => {
        console.error(`[AsyncStorage] 队列写入失败: ${key}`, e)
      })
    )

    await Promise.allSettled(promises)
    this.isProcessing = false

    if (this.pendingWrites.size > 0) {
      this._scheduleWrite()
    }
  }

  async setWithExpiry(key, value, ttl) {
    return this.set(key, value, { ttl })
  }

  async getWithExpiry(key, defaultValue = null) {
    const cached = this.cache.get(key)
    if (!cached) {
      const value = await this._getRaw(key)
      if (value === null) return defaultValue
      return value
    }

    if (cached.ttl && Date.now() - cached.timestamp > cached.ttl) {
      this.cache.delete(key)
      return defaultValue
    }

    return cached.value
  }

  async getWallpaperList() {
    const cached = this.cache.get(StorageKeys.STORAGE_CLASS_LIST)
    if (cached) {
      const ttl = StorageConfig.cacheExpiry.storageClassList
      if (!ttl || Date.now() - cached.timestamp < ttl) {
        return cached.value
      }
    }
    return this.get(StorageKeys.STORAGE_CLASS_LIST, [])
  }

  async setWallpaperList(list) {
    return this.set(StorageKeys.STORAGE_CLASS_LIST, list)
  }

  async appendWallpaperList(items) {
    const current = await this.getWallpaperList()
    const newList = [...current, ...items]
    return this.set(StorageKeys.STORAGE_CLASS_LIST, newList)
  }

  async clearWallpaperList() {
    return this.remove(StorageKeys.STORAGE_CLASS_LIST)
  }

  async getBannerCache() {
    const ttl = StorageConfig.cacheExpiry.bannerCache
    return this.getWithExpiry(StorageKeys.BANNER_CACHE, null)
  }

  async setBannerCache(data) {
    const ttl = StorageConfig.cacheExpiry.bannerCache
    return this.set(StorageKeys.BANNER_CACHE, data, { ttl })
  }

  async getClassifyCache() {
    const ttl = StorageConfig.cacheExpiry.classifyCache
    return this.getWithExpiry(StorageKeys.CLASSIFY_CACHE, null)
  }

  async setClassifyCache(data) {
    const ttl = StorageConfig.cacheExpiry.classifyCache
    return this.set(StorageKeys.CLASSIFY_CACHE, data, { ttl })
  }

  async getUserStats() {
    return {
      downloadCount: await this.get(StorageKeys.USER_DOWNLOAD_COUNT, 0),
      scoreCount: await this.get(StorageKeys.USER_SCORE_COUNT, 0)
    }
  }

  async incrementDownloadCount() {
    const current = await this.get(StorageKeys.USER_DOWNLOAD_COUNT, 0)
    return this.set(StorageKeys.USER_DOWNLOAD_COUNT, current + 1)
  }

  async incrementScoreCount() {
    const current = await this.get(StorageKeys.USER_SCORE_COUNT, 0)
    return this.set(StorageKeys.USER_SCORE_COUNT, current + 1)
  }

  async setUserStats(stats) {
    const promises = []
    if (stats.downloadCount !== undefined) {
      promises.push(this.set(StorageKeys.USER_DOWNLOAD_COUNT, stats.downloadCount))
    }
    if (stats.scoreCount !== undefined) {
      promises.push(this.set(StorageKeys.USER_SCORE_COUNT, stats.scoreCount))
    }
    await Promise.all(promises)
  }

  async flush() {
    if (this.pendingWrites.size > 0) {
      await this._processQueue()
    }
  }

  getCacheStats() {
    return {
      cacheSize: this.cache.size,
      pendingWrites: this.pendingWrites.size,
      isProcessing: this.isProcessing
    }
  }
}

const asyncStorage = new AsyncStorage()

export default asyncStorage
